// UpdateCompanyStatus is the resolver for the updateCompanyStatus field.
func (r *mutationResolver) UpdateCompanyStatus(ctx context.Context, id string, status string) (*model.Company, error) {
	// 1. Get Company
	comp, err := r.CompanyRepo.GetByID(ctx, id)
	if err != nil {
		if err == company.ErrNotFound {
			return nil, fmt.Errorf("company not found")
		}
		return nil, fmt.Errorf("failed to get company: %w", err)
	}

	// 2. Validate and Update Status
	// Lowercase the input status to match domain enum (e.g. SUSPENDED -> suspended)
	st := company.CompanyStatus(strings.ToLower(status))
	if !st.IsValid() {
		return nil, fmt.Errorf("invalid status: %s", status)
	}

	// Update entity
	switch st {
	case company.StatusActive:
		comp.Activate()
	case company.StatusSuspended:
		comp.Suspend()
	case company.StatusPending:
		// Logic for pending? Revert to pending?
		comp.Status = company.StatusPending
		comp.UpdatedAt = time.Now()
	}

	// 3. Persist
	if err := r.CompanyRepo.Update(ctx, comp); err != nil {
		return nil, fmt.Errorf("failed to update company: %w", err)
	}

	return &model.Company{
		ID:           comp.ID,
		TenantID:     comp.TenantID,
		Cnpj:         comp.CNPJ,
		RazaoSocial:  comp.RazaoSocial,
		NomeFantasia: comp.NomeFantasia,
		Status:       string(comp.Status),
		Address: &model.Address{
			Logradouro:  comp.Endereco.Logradouro,
			Numero:      comp.Endereco.Numero,
			Complemento: &comp.Endereco.Complemento,
			Bairro:      comp.Endereco.Bairro,
			Cidade:      comp.Endereco.Cidade,
			Uf:          comp.Endereco.UF,
			Cep:         comp.Endereco.CEP,
		},
		CreatedAt: comp.CreatedAt.Format(time.RFC3339),
		UpdatedAt: comp.UpdatedAt.Format(time.RFC3339),
	}, nil
}

