// Companies is the resolver for the companies field.
func (r *queryResolver) Companies(ctx context.Context, filter *model.CompanyFilterInput, page *int, limit *int) (*model.CompanyConnection, error) {
	// Get user ID from context to filter companies
	userID, ok := middleware.UserIDFromContext(ctx)
	if !ok {
		if ctx.Value(middleware.UserIDKey) != nil {
			return nil, fmt.Errorf("invalid user id in context")
		}
		return nil, fmt.Errorf("unauthorized")
	}

	// Fetch companies for user
	companiesWithRole, err := r.CompanyService.GetCompaniesForUser(ctx, userID)
	if err != nil {
		return nil, fmt.Errorf("failed to list companies: %w", err)
	}

	// Map to GraphQL model
	var items []*model.Company
	for _, c := range companiesWithRole {
		// Filter by status if provided in filter?
		// For now just return all associated companies

		items = append(items, &model.Company{
			ID:           c.Company.ID,
			TenantID:     c.Company.TenantID,
			Cnpj:         c.Company.CNPJ,
			RazaoSocial:  c.Company.RazaoSocial,
			NomeFantasia: c.Company.NomeFantasia,
			Status:       string(c.Company.Status),
			Address: &model.Address{
				Logradouro:  c.Company.Endereco.Logradouro,
				Numero:      c.Company.Endereco.Numero,
				Complemento: &c.Company.Endereco.Complemento,
				Bairro:      c.Company.Endereco.Bairro,
				Cidade:      c.Company.Endereco.Cidade,
				Uf:          c.Company.Endereco.UF,
				Cep:         c.Company.Endereco.CEP,
			},
			CreatedAt: c.Company.CreatedAt.Format(time.RFC3339),
			UpdatedAt: c.Company.UpdatedAt.Format(time.RFC3339),
		})
	}

	// Pagination handling (slice in memory since service returns all)
	// This is temporary until repo supports pagination with user filter
	count := len(items)

	p := 1
	if page != nil && *page > 0 {
		p = *page
	}
	l := 10
	if limit != nil && *limit > 0 {
		l = *limit
	}
	start := (p - 1) * l
	end := start + l

	if start > count {
		start = count
	}
	if end > count {
		end = count
	}

	pagedItems := items[start:end]

	return &model.CompanyConnection{
		Items: pagedItems,
		Count: count,
	}, nil
}

