// CompanyUserAdded is the resolver for the companyUserAdded field.
func (r *subscriptionResolver) CompanyUserAdded(ctx context.Context, companyID string) (<-chan *model.CompanyUser, error) {
	ch := make(chan *model.CompanyUser, 1)

	handler := func(ctx context.Context, e event.Event) error {
		payload, ok := e.Payload.(event.CompanyUserAddedPayload)
		if !ok {
			// Try to cast from map if coming from JSON
			// In in-memory bus it preserves type if passed as struct, but good to be safe if serialized
			// Here assuming struct preservation or we need better unmarshaling
			return nil
		}

		if payload.CompanyID != companyID {
			return nil
		}

		modelUser := &model.CompanyUser{
			CompanyID: payload.CompanyID,
			UserID:    payload.UserID,
			Role:      payload.Role,
			Status:    "active", // Default status for added user
			JoinedAt:  time.Now().Format(time.RFC3339),
		}

		// Non-blocking send
		select {
		case ch <- modelUser:
		default:
			// Client likely disconnected or slow
		}
		return nil
	}

	unsubscribe := r.EventBus.Subscribe(event.CompanyUserAdded, handler)

	// Clean up when context is done
	go func() {
		<-ctx.Done()
		unsubscribe()
	}()

	return ch, nil
}

